  let score = 0;
  for (const value of values) {
    let current = Math.abs(value);
    let bits = 0;
    while (current > 0) {
      bits += current & 1;
      current >>= 1;
    }
    if (value % 2 === 0) score += bits;
    else score -= bits;
  }
  return score;
}

