            elif ch == "E":
                end = (row, col)
    if start is None or end is None:
        return -1
    queue = deque([(start[0], start[1], 0)])
    seen = {start}
    while queue:
        row, col, dist = queue.popleft()
        if (row, col) == end:
            return dist
        for row_delta, col_delta in ((1, 0), (-1, 0), (0, 1), (0, -1)):
