import java.util.*;
class Solution {
    public static int max_non_adjacent_sum_011(List<Integer> values) {
        int include = 0;
        int exclude = 0;
        for (int value : values) {
            int nextInclude = exclude + value;
            int nextExclude = Math.max(include, exclude);
            include = nextInclude;
            exclude = nextExclude;
        }
        return Math.max(Math.max(include, exclude), 0);
    }
}

