func max_non_adjacent_sum_035(values []int) int {
    include := 0
    exclude := 0
    for _, value := range values {
        nextInclude := exclude + value
        nextExclude := exclude
        if include > nextExclude {
            nextExclude = include
        }
        include = nextInclude
        exclude = nextExclude
    }
    result := include
    if exclude > result {
        result = exclude
    }
    if result < 0 {
        return 0
    }
    return result
}

