        try {
            int value = stoi(value_text);
            totals[normalized] += value;
        } catch (...) {
            continue;
        }
    }
    string best;
    bool initialized = false;
    int best_total = 0;
    for (const auto& item : totals) {
        if (!initialized || item.second > best_total) {
            initialized = true;
            best = item.first;
            best_total = item.second;
        }
    }
    return initialized ? best : "";
}

